// ─── Types ────────────────────────────────────────────────────────────────────

export interface GigWorker {
  worker_id: string;
  name: string;
  gender: "male";
  platform: "Swiggy" | "Zomato" | "Blinkit" | "Uber" | "Ola" | "Porter";
  city: "Delhi" | "Mumbai" | "Bangalore" | "Hyderabad" | "Pune";
  city_tier: "Tier 1";
  days_active_last_30: number;
  avg_daily_income: number;
  hours_per_day: number;
  total_earnings_last_30_days: number;
  peak_hours: "morning" | "afternoon" | "evening" | "night";
  risk_zone: "low" | "medium" | "high";
  weather_exposure_days: number;
  aqi_exposure_days: number;
  joining_date: string;
  last_active_date: string;
}

