// ─── Utility Functions ────────────────────────────────────────────────────────

/**
 * Returns a random worker from the dataset.
 */
export function getRandomWorker(): GigWorker {
  return gigWorkers[Math.floor(Math.random() * gigWorkers.length)];
}

/**
 * Returns all workers from the specified city.
 * Case-insensitive match.
 */
export function getWorkersByCity(city: string): GigWorker[] {
  const normalized = city.trim().toLowerCase();
  return gigWorkers.filter(w => w.city.toLowerCase() === normalized);
}

/**
 * Returns all workers in the high risk zone.
 */
export function getHighRiskWorkers(): GigWorker[] {
  return gigWorkers.filter(w => w.risk_zone === "high");
}

// ─── Derived Stats (bonus helpers) ───────────────────────────────────────────

/**
 * Returns workers grouped by city with aggregate stats.
 */
export function getCityStats() {
  const cities = ["Delhi", "Mumbai", "Bangalore", "Hyderabad", "Pune"] as const;
  return cities.map(city => {
    const workers = getWorkersByCity(city);
    const active = workers.filter(w => w.days_active_last_30 >= 20);
    const totalEarnings = workers.reduce((s, w) => s + w.total_earnings_last_30_days, 0);
    const avgIncome = Math.round(totalEarnings / workers.length);
    const highRisk = workers.filter(w => w.risk_zone === "high").length;
    return { city, total: workers.length, active: active.length, avgIncome, highRisk };
  });
}

/**
 * Returns inactive workers (0–3 days active in last 30 days).
 */
export function getInactiveWorkers(): GigWorker[] {
  return gigWorkers.filter(w => w.days_active_last_30 <= 3);
}

/**
 * Returns heavy workers (20+ days active in last 30 days).
 */
export function getHeavyWorkers(): GigWorker[] {
  return gigWorkers.filter(w => w.days_active_last_30 >= 20);
}
